+            .failure()
+            .stderr(predicate::str::contains("unknown style"));
+    }
+
+    #[test]
+    fn test_invalid_width_not_number() {
+        let mut cmd = glow_cmd();
+        cmd.arg("tests/fixtures/basic.md")
+            .arg("--width")
+            .arg("abc")
+            .arg("--no-pager")
+            .assert()
+            .failure();
+    }
